messages.content:
THOUGHT: The miscompile occurs when InstCombine inverts an ordered FCmp (like olt) and swaps select arms, but drops the select’s FMF (nnan/nsz). The precise spot is in visitSelectInst where the code canonicalizes min/max-like patterns and may swap arms based on a “Swapped” flag. We need to preserve FMF only in this select reconstruction, not broadly, to avoid introducing new transforms like minnum that break tests. I will narrow the patch to only use CreateSelectFMF in those specific places (keeping FMF from the original select), and revert any other broad changes.

```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@
-  if (SIFPOp) {
+  if (SIFPOp) {
@@
-      if (IsCastNeeded ||
+      if (IsCastNeeded ||
           (LHS->getType()->isFPOrFPVectorTy() &&
            ((CmpLHS != LHS && CmpLHS != RHS) ||
             (CmpRHS != LHS && CmpRHS != RHS)))) {
         CmpInst::Predicate MinMaxPred = getMinMaxPred(SPF, SPR.Ordered);

         Value *Cmp;
         if (CmpInst::isIntPredicate(MinMaxPred))
           Cmp = Builder.CreateICmp(MinMaxPred, LHS, RHS);
         else
           Cmp = Builder.CreateFCmpFMF(MinMaxPred, LHS, RHS,
                                       cast<Instruction>(SI.getCondition()));
-
-        Value *NewSI = Builder.CreateSelectFMF(Cmp, LHS, RHS, &SI, SI.getName(), &SI);
+        // Preserve fast-math flags when rebuilding the select for FP min/max patterns.
+        Value *NewSI = Builder.CreateSelectFMF(Cmp, LHS, RHS, &SI, SI.getName(), &SI);
         if (!IsCastNeeded)
           return replaceInstUsesWith(SI, NewSI);

         Value *NewCast = Builder.CreateCast(CastOp, NewSI, SelType);
         return replaceInstUsesWith(SI, NewCast);
       }
     }
   }

*** End Patch
PATCH
```

